using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string DocumentText { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences);
}

/// <summary>
/// Extractive summarizer that scores sentences by word frequency and returns the top-ranked ones
/// in their original document order.
/// </summary>
public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","can","could","of","in","to","for","with",
        "on","at","by","from","as","into","about","between","through","after",
        "above","below","out","off","over","under","then","than","too","very",
        "just","that","this","it","its","i","me","my","we","our","you","your",
        "he","him","his","she","her","they","them","their","what","which",
        "who","whom","when","where","how","not","no","nor","so","if"
    ];

    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
        {
            var joined = string.Join(" ", sentences);
            return (joined, sentences.Count, sentences.Count);
        }

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = sentences
            .Select((s, i) => (Index: i, Sentence: s, Score: ScoreSentence(s, wordFrequencies)))
            .ToList();

        // Pick the top-scoring sentences, then re-order by original position.
        var topSentences = scored
            .OrderByDescending(x => x.Score)
            .Take(maxSentences)
            .OrderBy(x => x.Index)
            .Select(x => x.Sentence);

        var summary = string.Join(" ", topSentences);
        return (summary, sentences.Count, maxSentences);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (!StopWords.Contains(word))
                {
                    freq[word] = freq.GetValueOrDefault(word) + 1;
                }
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> frequencies)
    {
        var words = TokenizeWords(sentence);
        if (words.Count == 0) return 0;

        double total = words
            .Where(w => !StopWords.Contains(w))
            .Sum(w => frequencies.GetValueOrDefault(w));

        // Normalise by word count to avoid bias toward long sentences.
        return total / words.Count;
    }

    private static List<string> TokenizeWords(string text)
    {
        return WordRegex()
            .Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = summarizer.Summarize(
            request.DocumentText,
            request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

